// utils/formatters.js
export function formatDate(d) { return d.toLocaleDateString(); }
export function formatCurrency(n) { return `$${n.toFixed(2)}`; }
export const DEFAULT_CURRENCY = 'USD';

// components/Button.jsx
export default function Button({ label, onClick }) {
  return <button onClick={onClick}>{label}</button>;
}

// Caller picks any identifier — no braces
import Button from './components/Button';
import Btn from './components/Button'; // also valid

// components/Button.jsx
export const BUTTON_SIZES = { sm: 32, md: 40, lg: 48 };

export function IconButton({ icon, onClick }) {
  return <button onClick={onClick}>{icon}</button>;
}

export default function Button({ label, onClick }) {
  return <button onClick={onClick}>{label}</button>;
}

// UserCard.jsx
// Small helper only used here — not exported
function Avatar({ src, alt }) {
  return <img src={src} alt={alt} className="avatar" />;
}

// Primary export
export default function UserCard({ user }) {
  return (
    <div className="user-card">
      <Avatar src={user.avatarUrl} alt={user.name} />
      <h3>{user.name}</h3>
    </div>
  );
}

// components/index.js  — barrel file
export { default as Button } from './Button';
export { default as Modal } from './Modal';
export { default as UserCard } from './UserCard';
export { IconButton } from './Button'; // named re-export

// Without barrel
import Button from '../components/Button';
import Modal from '../components/Modal';
import UserCard from '../components/UserCard';

// With barrel
import { Button, Modal, UserCard } from '../components';

// vite.config.js
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';
import path from 'path';

export default defineConfig({
  plugins: [react()],
  resolve: {
    alias: {
      '@': path.resolve(__dirname, './src'),
    },
  },
});

// Now imports are clean and location-independent
import { api } from '@/utils/api';
import Button from '@/components/Button';

// utils/formatters.js
export function formatDate(d) { ... } // named export

// App.jsx — wrong: no curly braces on a named export
import formatDate from './utils/formatters'; // undefined!

// Correct:
import { formatDate } from './utils/formatters';

// Button.jsx
export default function Button() { ... }

// Wrong — looks for a named export called 'Button'
import { Button } from './Button'; // undefined!

// Correct
import Button from './Button';

// Re-export everything from a file
export * from './Button';

// Re-export specific named export
export { IconButton } from './Button';

// Re-export default as named
export { default as Button } from './Button';

// Re-export and rename
export { IconButton as Icon } from './Button';

import { lazy, Suspense } from 'react';

// Dashboard is only downloaded when it's first rendered
const Dashboard = lazy(() => import('./pages/Dashboard'));

function App() {
  return (
    <Suspense fallback={<p>Loading...</p>}>
      <Dashboard />
    </Suspense>
  );
}

// Dashboard.jsx — using all patterns
import { useState } from 'react';
import { Button, Modal } from '@/components'; // barrel import via alias
import { useLocalStorage } from '@/hooks';   // barrel import via alias
import { formatDate } from '@/utils/formatters'; // direct named import

export default function Dashboard() {
  const [open, setOpen] = useLocalStorage('modalOpen', false);

  return (
    <div>
      <p>Last visit: {formatDate(new Date())}</p>
      <Button label="Open settings" onClick={() => setOpen(true)} />
      {open && <Modal onClose={() => setOpen(false)} />}
    </div>
  );
}

// types/user.ts
export interface User {
  id: number;
  name: string;
  avatarUrl: string;
}

export type UserRole = 'admin' | 'viewer' | 'editor';

// UserCard.tsx
import type { User, UserRole } from '@/types/user'; // type-only — erased at build time
import { useState } from 'react';                    // value import — stays in bundle

interface Props {
  user: User;
  role: UserRole;
}

export default function UserCard({ user, role }: Props) {
  return <div>{user.name} ({role})</div>;
}

import * as Formatters from '@/utils/formatters';

// Access each export via the namespace
console.log(Formatters.formatDate(new Date()));
console.log(Formatters.formatCurrency(19.99));

// main.jsx
import './index.css';           // applies global styles
import 'reflect-metadata';     // runs polyfill, exports nothing we need
import './i18n/setup';         // initializes i18n before app renders
import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

ReactDOM.createRoot(document.getElementById('root')).render(<App />);

// Button.test.jsx — direct import, not via barrel
import { render, screen } from '@testing-library/react';
import Button from './Button'; // exact file, not '@/components'

test('renders the label', () => {
  render(<Button label="Submit" onClick={() => {}} />);
  expect(screen.getByText('Submit')).toBeInTheDocument();
});
